for field in fields {
    if allow_transparent(field, derive) {
        if transparent_field.is_some() {
            cx.error_spanned_by(
                cont.original,
                "#[serde(transparent)] requires struct to have at most one transparent field",
            );
            return;
        }
        transparent_field = Some(field);
    }
}

while !ptr::eq(guard.start, guard.end) {
    // SAFETY: `start` is always initialized if `start != end`.
    let waker = unsafe { ptr::read(guard.start) };
    // SAFETY: The resulting pointer is in bounds or one after the length of the same object.
    guard.start = unsafe { guard.start.add(1) };
    // If this panics, then `guard` will clean up the remaining wakers.
    waker.wake();
}

if stolen {
    // This job was stolen!  Reset the number of desired splits to the
    // thread count, if that's more than we had remaining anyway.
    self.splits = Ord::max(crate::current_num_threads(), self.splits / 2);
    true
} else if splits > 0 {
    // We have splits remaining, make it so.
    self.splits /= 2;
    true
} else {
    // Not stolen, and no more splits -- we're done!
    false
}

for i in 0..len {
    // Safety: InplaceIterable contract guarantees that for every element we read
    // one slot in the underlying storage will have been freed up and we can immediately
    // write back the result.
    unsafe {
        let dst = dst_buf.add(i);
        debug_assert!(dst as *const _ <= end, "InPlaceIterable contract violation");
        ptr::write(dst, self.__iterator_get_unchecked(i));
        // Since this executes user code which can panic we have to bump the pointer
        // after each step.
        drop_guard.dst = dst.add(1);
    }
}

loop {
    // SAFETY: the caller must guarantee that the pointer is valid for read and write
    // and aligned to the element size.
    let curval_aligned = unsafe { atomic_load_aligned::<T>(aligned_ptr) };
    let curval = extract_aligned(curval_aligned, shift, mask);
    if curval != oldval {
        return curval;
    }
    let newval_aligned = insert_aligned(curval_aligned, newval, shift, mask);
    // SAFETY: the caller must guarantee that the pointer is valid for read and write
    // and aligned to the element size.
    if unsafe { __kuser_cmpxchg(curval_aligned, newval_aligned, aligned_ptr) } {
        return oldval;
    }
}

for &(upper, lowercount) in singletonuppers {
    let lowerend = lowerstart + lowercount as usize;
    if xupper == upper {
        for &lower in &singletonlowers[lowerstart..lowerend] {
            if lower == x as u8 {
                return false;
            }
        }
    } else if xupper < upper {
        break;
    }
    lowerstart = lowerend;
}

for command_def in &command_defs {
  let mut wrapper = command_def.path.clone();
  let last = super::path_to_command(&mut wrapper);

  // the name of the actual command function
  let command = last.ident.clone();

  // set the path to the command function wrapper
  last.ident = super::format_command_wrapper(&command);

  commands.push(command);
  wrappers.push(wrapper);
}

for p in &rule.template.tokens {
    if let PatternElement::Placeholder(placeholder) = p {
        if !defined_placeholders.contains(&placeholder.ident) {
            undefined.push(placeholder.ident.to_string());
        }
        if !placeholder.constraints.is_empty() {
            bail!("Replacement placeholders cannot have constraints");
        }
    }
}

match param.pat() {
    // remove suggestions for patterns that already exist
    // if the type is missing we are checking the current param to be completed
    // in which case this would find itself removing the suggestions due to itself
    Some(pattern) if param.ty().is_some() => {
        let binding = pattern.to_smolstr();
        file_params.retain(|_, v| v != &binding);
    }
    _ => (),
}

for (range, spec) in collector.specifiers {
  if let Some(rewritten) = rewrite_specifier(&spec) {
    // Extract dependencies from the specifier
    if let Some((name, version)) = extract_package_dependency(&spec) {
      dependencies.insert(name, version);
    }

    let byte_range = range.as_byte_range(text_info.range().start);
    text_changes.push(TextChange {
      range: byte_range,
      new_text: rewritten,
    });
  }
}

if !verbatim {
    if let Some(libname) = libname.strip_circumfix("lib", ".a") {
        // this is a unix style filename so trim prefix & suffix
        Some(libname)
    } else if let Some(libname) = libname.strip_suffix(".lib") {
        // this is a Windows style filename so just trim the suffix
        Some(libname)
    } else {
        None
    }
} else {
    None
}

loop {
    // SAFETY: the caller must guarantee that the pointer is valid for read and write
    // and aligned to the element size.
    let curval = unsafe { T::load_relaxed(ptr) };
    let newval = f(curval);
    // SAFETY: the caller must guarantee that the pointer is valid for read and write
    // and aligned to the element size.
    if unsafe { T::cmpxchg(ptr, curval, newval) } == curval {
        return g(curval, newval);
    }
}

if let Some(WithOverflow { nested_goals, result }) =
            entry.with_overflow.get(&additional_depth)
            && candidate_is_applicable(nested_goals)
        {
            return Some(CacheData {
                result: cx.get_tracked(result),
                required_depth: additional_depth,
                encountered_overflow: true,
                nested_goals,
            });
        }

#[inline]
    unsafe fn with_inner<F, R>(&self, f: F) -> R
    where
        F: FnOnce(&mut Option<Rc<T>>) -> R,
    {
        // safety: This type is not Sync, so concurrent calls of this method
        // cannot happen. Furthermore, the caller guarantees that the method is
        // not called recursively. Finally, this is the only place that can
        // create mutable references to the inner Rc. This ensures that any
        // mutable references created here are exclusive.
        self.inner.with_mut(|ptr| f(unsafe { &mut *ptr }))
    }

if head >> SHIFT != tail >> SHIFT {
    // The block can be null here only if a sender is in the process of initializing the
    // channel while another sender managed to send a message by inserting it into the
    // semi-initialized channel and advanced the tail.
    // In that case, just wait until it gets initialized.
    while block.is_null() {
        backoff.snooze();
        block = self.head.block.swap(ptr::null_mut(), Ordering::AcqRel);
    }
}

if is_generic(instance) {
    // For generics we might find re-usable upstream instances. If there
    // is one, we rely on the symbol being instantiated locally.
    instance.upstream_monomorphization(tcx).unwrap_or(LOCAL_CRATE)
} else {
    // For non-generic things that need to avoid naming conflicts, we
    // always instantiate a copy in the local crate.
    LOCAL_CRATE
}

if rule.pattern.contains_self {
    // If the pattern contains `self` we restrict the scope of the search to just the
    // current method. No other method can reference the same `self`. This makes the
    // behavior of `self` consistent with other variables.
    if let Some(current_function) = self.resolution_scope.current_function() {
        self.slow_scan_node(&current_function, rule, &None, matches_out);
    }
    return;
}

for pkg in &metadata.packages {
    if pkg.targets.iter().any(|target| target.is_proc_macro()) {
        check.error(format!(
            "proc macro `{}` is not allowed as standard library dependency.\n\
            Using proc macros in the standard library would break cross-compilation \
            as proc-macros don't get shipped for the host tuple.",
            pkg.name
        ));
    }
}

if let mir::Operand::Move(place) = operand
            && let Some(local) = place.as_local()
        {
            // For backward compatibility with the MaybeMutBorrowedLocals used in an earlier
            // implementation we retain qualif if a local had been borrowed before. This might
            // not be strictly necessary since the local is no longer initialized.
            if !self.state.borrow.contains(local) {
                self.state.qualif.remove(local);
            }
        }

if source_fd.get_readiness_mut().fulfills_interest(&interest) {
    // The requested readiness is currently already fulfilled for the provided source.
    // Instead of actually blocking the thread, we just run the callback function.
    callback.call(this, UnblockKind::Ready)
} else {
    // The I/O readiness is currently not fulfilled. We block the thread
    // until the readiness is fulfilled and execute the callback then.
    this.block_thread(BlockReason::IO, deadline, callback);
    interp_ok(())
}

if let Some(old_locked_count) = this.mutex_unlock(&mutex_ref)? {
    if old_locked_count != 1 {
        throw_unsup_format!(
            "awaiting a condvar on a mutex acquired multiple times is not supported"
        );
    }
} else {
    throw_ub_format!(
        "awaiting a condvar on a mutex that is unlocked or owned by a different thread"
    );
}

if might_have_negative_value(operand_type) {
    span_lint_and_then(
        cx,
        MODULO_ARITHMETIC,
        expr.span,
        "you are using modulo operator on types that might have different signs",
        |diag| {
            diag.note("double check for expected result especially when interoperating with different languages");
            if operand_type.is_integral() {
                diag.note("or consider using `rem_euclid` or similar function");
            }
        },
    );
}

for (elem, start) in self.pending.iter_enumerated_mut() {
    if let Some(start) = start.take() {
        debug_assert!(start <= self.current);
        // We are ending a block, mark all live locals as live up to `current`,
        // including that position (which is still inside the block).
        self.values.append_range(elem, start..=self.current);
    }
}

if self.default_mode_span.is_none_or(|(_, old_mutbl)| min_mutbl < old_mutbl) {
    // This changes the default binding mode to `ref` or `ref mut`. Return the old mode so
    // it can be reinstated when we leave the pattern.
    self.default_mode_span.replace((pat_span, min_mutbl))
} else {
    // This does not change the default binding mode; it was already `ref` or `ref mut`.
    self.default_mode_span
}

if let Some(ref span) = span
            // If this code originates in a foreign macro, aka something that this crate
            // did not itself author, then it's likely that there's nothing this crate
            // can do about it. We probably want to skip the lint entirely.
            && span.primary_spans().iter().any(|s| s.in_external_macro(sess.source_map()))
        {
            true
        } else {
            false
        }

if let Some(place) = place
            && let Some(extra) = &pattern.extra
        {
            for &Ascription { ref annotation, variance } in &extra.ascriptions {
                ascriptions.push(super::Ascription {
                    source: place,
                    annotation: annotation.clone(),
                    variance,
                });
            }
        }

if k < limit {
    // oops, we cannot even produce *one* digit.
    // this is possible when, say, we've got something like 9.5 and it's being rounded to 10.
    // we return an empty buffer, with an exception of the later rounding-up case
    // which occurs when `k == limit` and has to produce exactly one digit.
    0
} else if ((k as i32 - limit as i32) as usize) < buf.len() {
    (k - limit) as usize
} else {
    buf.len()
}

if let Some(pointee) = this.ty.builtin_deref(false) {
    let pointee = cx.layout_of(pointee)?;
    // We need to ensure that the LLVM attributes `aligned` and `dereferenceable(size)` are satisfied.
    if pointee.align.bytes() > 1 {
        // 0x01-filling is not aligned.
        return Ok(false);
    }
    if pointee.size.bytes() > 0 {
        // A 'fake' integer pointer is not sufficiently dereferenceable.
        return Ok(false);
    }
}

if val.layout.is_aggregate() {
    if let Some(unit) = val.layout.homogeneous_aggregate(cx).ok().and_then(|ha| ha.unit()) {
        let size = val.layout.size;
        // This size check also catches over-aligned scalars as `size` will be rounded up to a
        // multiple of the alignment, and the default alignment of all scalar types on wasm
        // equals their size.
        if unit.size == size {
            val.cast_to(unit);
            return true;
        }
    }
}

if new_cap > old_cap {
    deque.buf.reserve(actual_len, additional);
    // If new_cap doesn't panic, we can safely set the `VecDeque` len to its
    // actual len; this needs to be done in order to set deque.head correctly
    // on `VecDeque::handle_capacity_increase`
    deque.len = actual_len;
    // SAFETY: this cannot panic since our internal buffer's new_cap should
    // be bigger than the passed in old_cap
    unsafe {
        deque.handle_capacity_increase(old_cap);
    }
}
